import { useState } from 'react'
import { Navigate } from 'react-router-dom'
import { useAuthStore } from '../stores/authStore'

export default function LoginPage() {
  const isAuthenticated = useAuthStore((state) => state.isAuthenticated)
  const login = useAuthStore((state) => state.login)
  const loading = useAuthStore((state) => state.loading)
  const error = useAuthStore((state) => state.error)
  const [form, setForm] = useState({
    email: 'analyst@example.com',
    password: 'demo123',
  })

  if (isAuthenticated) {
    return <Navigate to="/" replace />
  }

  const handleSubmit = async (event) => {
    event.preventDefault()
    await login(form.email, form.password)
  }

  return (
    <div className="flex min-h-screen items-center justify-center bg-slate-950 px-6 text-white">
      <div className="grid max-w-5xl gap-8 lg:grid-cols-[1.1fr_0.9fr]">
        <section className="rounded-[36px] border border-cyan-400/10 bg-[radial-gradient(circle_at_top_left,_rgba(34,211,238,0.16),_transparent_35%),linear-gradient(180deg,_rgba(15,23,42,0.95),_rgba(2,6,23,0.95))] p-10">
          <p className="text-xs uppercase tracking-[0.35em] text-cyan-300">SentimentIQ</p>
          <h1 className="mt-6 text-5xl font-semibold leading-tight">
            Diagnose why customer sentiment drops before the business impact compounds.
          </h1>
          <p className="mt-6 max-w-xl text-base text-slate-300">
            Upload reviews, classify them with VADER and Transformers, extract aspects and topics, then isolate the
            earliest degrading experience in one local-only workspace.
          </p>
        </section>
        <form onSubmit={handleSubmit} className="rounded-[36px] border border-white/10 bg-white/5 p-10 backdrop-blur">
          <p className="text-xs uppercase tracking-[0.25em] text-orange-300">Local access</p>
          <h2 className="mt-4 text-3xl font-semibold">Sign in</h2>
          <div className="mt-8 space-y-4">
            <input
              className="w-full rounded-2xl border border-white/10 bg-slate-900/80 px-4 py-4 text-white outline-none"
              value={form.email}
              onChange={(event) => setForm((state) => ({ ...state, email: event.target.value }))}
              placeholder="Email"
            />
            <input
              type="password"
              className="w-full rounded-2xl border border-white/10 bg-slate-900/80 px-4 py-4 text-white outline-none"
              value={form.password}
              onChange={(event) => setForm((state) => ({ ...state, password: event.target.value }))}
              placeholder="Password"
            />
          </div>
          {error ? <p className="mt-4 text-sm text-rose-300">{error}</p> : null}
          <button
            type="submit"
            disabled={loading}
            className="mt-8 w-full rounded-2xl bg-cyan-300 px-4 py-4 font-semibold text-slate-950 transition hover:bg-cyan-200 disabled:opacity-60"
          >
            {loading ? 'Signing in...' : 'Enter workspace'}
          </button>
          <div className="mt-6 rounded-2xl border border-white/10 bg-slate-900/60 p-4 text-sm text-slate-300">
            Demo account: <span className="text-white">analyst@example.com / demo123</span>
          </div>
        </form>
      </div>
    </div>
  )
}
